package com.nutrisense.entity;
import jakarta.persistence.*; import lombok.*; import java.math.*; import java.time.*;
@Getter @Setter @Builder @NoArgsConstructor @AllArgsConstructor @Entity @Table(name="diet_plan_meals") public class DietPlanMeal { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="diet_plan_id",nullable=false) private DietPlan dietPlan; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="meal_type_id",nullable=false) private MealType mealType; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="food_id",nullable=false) private Food food; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="serving_id") private FoodServing serving; @Column(precision=8,scale=2) private BigDecimal quantity; @Enumerated(EnumType.STRING) @Column(name="day_of_week",length=10) private DayOfWeek dayOfWeek; @Column(name="created_at",insertable=false,updatable=false) private Instant createdAt; }
